import network
import time
import ssl
from umqtt.simple import MQTTClient
from machine import Pin
import ubinascii
import machine
import os

WIFI_SSID = os.getenv('WIFI_SSID')
WIFI_PASSWORD = os.getenv('WIFI_PASSWORD')
MQTT_BROKER = os.getenv('MQTT_BROKER')
MQTT_PORT = int(os.getenv('MQTT_PORT', '8883'))
MQTT_USER = os.getenv('MQTT_USER')
MQTT_PASSWORD = os.getenv('MQTT_PASSWORD')
MQTT_TOPIC = 'sensors/temp'

def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print('Connecting to WiFi...')
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 0
        while not wlan.isconnected() and timeout < 20:
            time.sleep(1)
            timeout += 1
        if not wlan.isconnected():
            raise Exception('WiFi connection failed')
    print('WiFi connected:', wlan.ifconfig())

def validate_temperature(temp):
    if not isinstance(temp, (int, float)):
        raise ValueError('Temperature must be numeric')
    if temp < -50 or temp > 150:
        raise ValueError('Temperature out of valid range')
    return round(temp, 2)

def read_temperature():
    import random
    temp = 20 + random.uniform(-5, 15)
    return validate_temperature(temp)

def create_mqtt_client():
    client_id = ubinascii.hexlify(machine.unique_id())
    
    if not all([MQTT_BROKER, MQTT_USER, MQTT_PASSWORD]):
        raise ValueError('MQTT credentials not configured')
    
    client = MQTTClient(
        client_id=client_id,
        server=MQTT_BROKER,
        port=MQTT_PORT,
        user=MQTT_USER,
        password=MQTT_PASSWORD,
        ssl=True,
        ssl_params={'server_hostname': MQTT_BROKER}
    )
    
    return client

def publish_sensor_data():
    connect_wifi()
    
    client = create_mqtt_client()
    
    try:
        client.connect()
        print('Connected to MQTT broker')
        
        while True:
            try:
                temperature = read_temperature()
                
                payload = str(temperature).encode('utf-8')
                
                if len(payload) > 256:
                    raise ValueError('Payload too large')
                
                client.publish(MQTT_TOPIC, payload, qos=1)
                print(f'Published temperature: {temperature}°C')
                
                time.sleep(60)
                
            except ValueError as e:
                print(f'Validation error: {e}')
                time.sleep(5)
            except Exception as e:
                print(f'Error publishing data: {e}')
                time.sleep(10)
                
    except Exception as e:
        print(f'MQTT connection error: {e}')
    finally:
        try:
            client.disconnect()
        except:
            pass

if __name__ == '__main__':
    publish_sensor_data()